query:
START TRANSACTION;

DELETE FROM purchases
WHERE orderId IN (SELECT id FROM orders WHERE userId = 3);

DELETE FROM orderHistory
WHERE orderId IN (SELECT id FROM orders WHERE userId = 3);

DELETE FROM couponUsages
WHERE orderId IN (SELECT id FROM orders WHERE userId = 3);

DELETE FROM pointsTransactions
WHERE referenceType = 'order'
  AND referenceId IN (SELECT id FROM orders WHERE userId = 3);

DELETE FROM orderItems
WHERE orderId IN (SELECT id FROM orders WHERE userId = 3);

DELETE FROM payments
WHERE orderId IN (SELECT id FROM orders WHERE userId = 3);

DELETE FROM orders
WHERE userId = 3;

COMMIT;

